window.allTests["test_u3_degisim_5"] = [
    {
        soru: "<i>\"Osmanlı padişahı, otoritesini pekiştirmek için devşirme kökenli kapıkullarına dayanmayı tercih etti. Bu kişiler kölece bağlılıklarıyla ayrıcalıklı bir statüye sahip olurken padişah da Türk-Müslüman aristokrasisinin baskısından büyük ölçüde kurtulmuş oldu. Böylece merkezi otorite, kalıtsal yerel güçlerin önüne geçerek kurumsallaştı.\"</i><br><br><b>İnalcık'ın bu değerlendirmesine göre kapıkulu sisteminin Osmanlı siyasi yapısına en temel katkısı nedir?</b>",
        secenekler: [
            "A) Yeniçeri ocağının savaş kapasitesini kalıcı biçimde artırması",
            "B) Devşirme kökenli yöneticilerin İslam hukukunu uygulamasını sağlaması",
            "C) Padişahın kalıtsal Türk-Müslüman aristokrasisine bağımlılığını zayıflatması",
            "D) Tımar sistemini genişleterek taşra yönetimini merkezden bağımsızlaştırması",
            "E) Osmanlı ordusunun ateşli silah teknolojisini benimsemesini hızlandırması"
        ],
        cevap: "C) Padişahın kalıtsal Türk-Müslüman aristokrasisine bağımlılığını zayıflatması",
        aciklama: "Metin, padişahın otoritesini güçlendirmek için devşirme kökenli kapıkullara dayandığını ve böylece Türk-Müslüman aristokrasisinin baskısından kurtulduğunu açıkça ifade etmektedir. Bu personelin kariyer olanakları ve yükselişi tamamen sultan iradesine bağlı olduğundan, bu kişiler özerk bir güç odağı oluşturamıyordu. Doğru yanıt C'dir: kalıtsal güçlerin devre dışı bırakılarak merkezi otoritenin kurumsallaşması."
    },
    {
        soru: "<i>\"Osmanlı devleti, kuruluş döneminde gazi geleneğine dayalı yarı göçebe bir siyasi birlik iken, 15. yüzyılın ikinci yarısıyla birlikte çok katmanlı bir bürokrasiye dönüştü. Bu dönüşüm, fetih coğrafyasının genişlemesiyle birlikte yönetim ihtiyacının artmasından kaynaklanıyordu; ancak söz konusu bürokratik yapı hiçbir zaman tek tip ve katı biçimde işlemedi; yerel özgünlükler merkezi yapıyla iç içe geçmeyi sürdürdü.\"</i><br><br><b>Kafadar'ın tespitine göre Osmanlı'nın kuruluştan 15. yüzyıl sonrasına uzanan yönetimsel dönüşümünü en iyi hangi ifade özetler?</b>",
        secenekler: [
            "A) Osmanlı yönetimi, gazi geleneğini büyük ölçüde koruyarak fetih coğrafyasını genişletti.",
            "B) Bürokratik merkezileşme, yerel yapıların tamamen tasfiyesiyle sağlandı.",
            "C) Fethin getirdiği idari zorunluluklar, bürokrasiyi doğurdu; ancak yerel farklılıklar bu yapıyla varlığını sürdürdü.",
            "D) Osmanlı bürokrasisi, doğrudan Bizans kurumsal mirasını benimseyerek oluşturuldu.",
            "E) 15. yüzyılda Osmanlı, sabit askeri sınıflardan kurtularak sivil yönetime geçiş yaptı."
        ],
        cevap: "C) Fethin getirdiği idari zorunluluklar, bürokrasiyi doğurdu; ancak yerel farklılıklar bu yapıyla varlığını sürdürdü.",
        aciklama: "Kafadar, bürokratik dönüşümün fethin yarattığı yönetim ihtiyacından kaynaklandığını ve yerel özgünlüklerin merkezi yapıyla iç içe yaşamayı sürdürdüğünü belirtmektedir. A seçeneği gazi geleneğinin korunduğunu savunmakta; ancak metin bu geleneğin aşıldığını ima etmektedir. B seçeneği yerel yapıların tamamen tasfiyesiyle sağlandığını öne sürmekte; metin bunu açıkça reddetmektedir. Doğru yanıt C'dir."
    },
    {
        soru: "<i>\"Osmanlı tımar sistemi, fethedilen toprakların yönetimini ve sipahi ordusunun finansmanını eş zamanlı olarak çözen bir mekanizmaydı. Timarlı sipahiler, aldıkları dirliklerin gelirleri karşılığında sefere çıkmakla yükümlüydü ve bu yükümlülük devletin merkezi hazinesine yük bindirmeden düzenli bir atlı kuvvet oluşturmasını mümkün kılıyordu. Ancak 16. yüzyılın sonlarından itibaren bu yapı, ateşli silahların savaş tekniğini değiştirmesiyle işlevsizleşmeye başladı.\"</i><br><br><b>İnalcık'ın açıklamasına göre tımar sisteminin işlevsizleşmesinin temel nedeni nedir?</b>",
        secenekler: [
            "A) Timarlı sipahilerin Yeniçeri ocağına dahil edilmesiyle oluşan kurumsal çatışma",
            "B) Ateşli silahların yaygınlaşmasıyla değişen savaş teknolojisi",
            "C) Merkezi hazinenin büyümesiyle tımar gelirlerinin önemini yitirmesi",
            "D) Osmanlı fethinin duraksayarak yeni tımar alanlarının tükenmesi",
            "E) Eyalet yöneticilerinin tımar gelirlerini merkeze aktarmayı reddetmesi"
        ],
        cevap: "B) Ateşli silahların yaygınlaşmasıyla değişen savaş teknolojisi",
        aciklama: "Metin, 16. yüzyılın sonlarında ateşli silahların savaş tekniğini değiştirdiğini ve bunun tımar sistemini işlevsizleştirdiğini açıkça belirtmektedir. Süvari ağırlıklı tımar sistemi, piyade ve ateşli silah gerektiren yeni savaş düzenine uyum sağlayamadı. Doğru yanıt B'dir."
    },
    {
        soru: "<i>\"16. yüzyıl boyunca Osmanlı ordusunun bel kemiğini oluşturan kapıkulu piyadeleri, sayı ve savaş etkinliği bakımından giderek büyüyen ateşli silah birlikleriyle desteklendi. Ancak bu genişleme özellikle 17. yüzyılda ocakların mali yükümlülükleri ve disiplin sorunlarını da beraberinde getirdi. Sefer dönemi dışında Kapıkulu birliklerinin giderek artan oranı İstanbul'da görev yapıyor, bu durum devlet mali kaynaklarını zorluyor ve siyasi istikrarsızlığa zemin hazırlıyordu.\"</i><br><br><b>Murphey'in aktardığı süreç değerlendirildiğinde, 17. yüzyılda kapıkulu birliklerinin siyasi istikrarsızlığa yol açmasının temel mekanizması nedir?</b>",
        secenekler: [
            "A) Kapıkulu birliklerinin Anadolu eyaletlerinde bağımsız üsler kurması",
            "B) İstanbul'da konuşlanan büyük sayıda kapıkulunun mali yük ve disiplin sorunları yaratması",
            "C) Kapıkulu komutanlarının tımar sistemini ele geçirerek taşra gücünü denetlemesi",
            "D) Sefer gelirlerinin azalmasıyla birlikte kapıkullarının ticarete yönelmesi",
            "E) Yabancı paralı askerlerin Kapıkulu sistemine dahil edilmesi"
        ],
        cevap: "B) İstanbul'da konuşlanan büyük sayıda kapıkulunun mali yük ve disiplin sorunları yaratması",
        aciklama: "Murphey, kapıkulu birliklerinin sefer dışı dönemlerde İstanbul'da birikmesinin mali yük ve disiplin sorunlarına yol açtığını ve bunun siyasi istikrarsızlık zemini hazırladığını belirtmektedir. Doğru yanıt B'dir."
    },
    {
        soru: "<i>\"Divan-ı Hümayun, Osmanlı merkez yönetiminin kararların alındığı ve uygulamaya konulduğu kurumsal kalbi idi. 15. yüzyılın ortalarına dek padişah divana bizzat başkanlık etmekte, hukuki ve yönetimsel kararları doğrudan vermekteydi. II. Mehmed'den itibaren padişah bu meclisten çekildi; görevi yürüten veziriazam, kafes arkasında izlediği öne sürülen hükümdarın işlevini fiilen üstlendi. Bu değişim, salt törensel bir düzenleme değil, iktidar dengesini yeniden tarif eden yapısal bir kırılmaydı.\"</i><br><br><b>Imber'ın aktarımına göre II. Mehmed'den itibaren gerçekleşen kurumsal değişiklik nasıl yorumlanmalıdır?</b>",
        secenekler: [
            "A) Padişahın dini meşruiyetini güçlendirmek amacıyla saltanat törenlerinin yeniden düzenlenmesi",
            "B) Veziriazamın salt protokol düzeyinde bir konum kazanarak yürütme yetkisini padişaha devretmesi",
            "C) Divan başkanlığının padişahtan veziriazama geçmesiyle iktidar dengesinin yapısal biçimde yeniden tanımlanması",
            "D) Osmanlı yönetim anlayışının İslam hukukuna uyum sağlamak için köklü biçimde dönüştürülmesi",
            "E) Divan toplantılarının sıklığının azaltılarak kararların taşra yöneticilerine bırakılması"
        ],
        cevap: "C) Divan başkanlığının padişahtan veziriazama geçmesiyle iktidar dengesinin yapısal biçimde yeniden tanımlanması",
        aciklama: "Imber, bu değişikliği salt törensel değil, iktidar dengesini yeniden tarif eden yapısal bir kırılma olarak nitelendirmektedir. Veziriazam artık divana fiilen hâkimdir. Doğru yanıt C'dir."
    },
    {
        soru: "<i>\"Osmanlı devleti, Batı Avrupa'daki muadillerinden farklı olarak merkezileşme sürecini şiddet tekeline geçişle değil, müzakere ve işbirliğini içeren esnek bir uzlaşma modeliyle yürüttü. Merkez, yerel aktörleri kriminalize etmek yerine sisteme dahil etmeyi tercih etti; böylece potansiyel muhalefet nötralize edilirken devlet ağları genişledi.\"</i><br><br><b>Barkey'in modeliyle Osmanlı devletinin merkezileşme stratejisi nasıl tanımlanabilir?</b>",
        secenekler: [
            "A) Silahla bastırma ve ağır vergilendirme yoluyla yerel direnişin kırılması",
            "B) Yerel aktörlerin sisteme dahil edilmesiyle oluşturulan uzlaşmacı merkezileşme",
            "C) Dini otorite aracılığıyla eyalet yöneticilerinin meşruiyetinin sağlanması",
            "D) Büyük şehirlerdeki ticaret sınıfıyla kurulan ekonomik ittifak",
            "E) Dışarıdan getirilen bürokratların eyaletlere atanmasıyla yerel güçlerin tasfiyesi"
        ],
        cevap: "B) Yerel aktörlerin sisteme dahil edilmesiyle oluşturulan uzlaşmacı merkezileşme",
        aciklama: "Barkey, Osmanlı'nın Batı Avrupa modelinden farklı olarak şiddet yerine müzakere ve sisteme dahil etme yoluyla merkezileştiğini vurgulamaktadır. Doğru yanıt B'dir."
    },
    {
        soru: "<i>İnalcık: \"17. yüzyıl Osmanlı mali-askeri krizinin kökeni tımarlı sipahi sisteminin çöküşüdür; merkezde kalabalıklaşan kapıkulu birlikleri hazineyi tüketirken tımar çürümesi taşra güvenliğini baltaladı.\"<br>Murphey: \"17. yüzyılda Osmanlı'nın yaşadığı askeri baskı, kronik bir sistemik çöküşten çok uluslararası konjonktürel faktörlerle örtüşmektedir; çünkü aynı dönem Avrupalı devletler de benzer maliye-ordu krizlerini yaşamaktaydı.\"</i><br><br><b>İnalcık ile Murphey'nin 17. yüzyıl Osmanlı askeri-mali krizine ilişkin yorumları arasındaki temel tarih yazımsal ayrım nedir?</b>",
        secenekler: [
            "A) İnalcık yapısal-içsel nedenleri ön plana alırken Murphey uluslararası bağlamı ve karşılaştırmalı bir perspektifi öne çıkarmaktadır.",
            "B) İnalcık kapıkulu birliklerini sağlıklı bulurken Murphey tımar sisteminin çöküşünü birincil neden saymaktadır.",
            "C) Her iki tarihçi de krizi yalnızca mali çöküş çerçevesinde ele almakta; askeri faktörleri göz ardı etmektedir.",
            "D) Murphey Osmanlı'nın istisnai bir çöküş yaşadığını savunurken İnalcık Avrupa devletleriyle benzerlik kurmaktadır.",
            "E) İnalcık Celali isyanlarını tek neden olarak gösterirken Murphey iklim değişikliğini esas almaktadır."
        ],
        cevap: "A) İnalcık yapısal-içsel nedenleri ön plana alırken Murphey uluslararası bağlamı ve karşılaştırmalı bir perspektifi öne çıkarmaktadır.",
        aciklama: "İki tarihçi arasındaki temel ayrım yapısal-içsel ile karşılaştırmalı-konjonktürel perspektifler arasındadır. İnalcık, tımarlı sipahi ve kapıkulu sistemlerindeki bozulmayı içsel bir çözülme olarak değerlendirirken Murphey krizin Avrupa ile eş zamanlı olduğuna dikkat çekerek küresel konjonktürel bir baskı olarak yaklaşmaktadır. Doğru yanıt A'dır."
    },
    {
        soru: "<i>\"Veziriazamlar, 16. yüzyılın ortasından itibaren padişahın erkek çocukları taşraya sancakbeyliği için gönderilmediğinde fiilen tek icra makamı haline geldiler. Bu durum, bürokraside yetki ve sorumluluğun tek bir elde yoğunlaşmasına yol açtı; hem fırsat hem de büyük bir güç çatışması riski doğurdu.\"</i><br><br><b>Finkel'in betimlemesine göre veziriazamın 16. yüzyıldan itibaren üstlendiği konumu en doğru tanımlayan seçenek hangisidir?</b>",
        secenekler: [
            "A) Şeyhülislamla güç dengeleyerek padişahın dini otoritesini sınırladı.",
            "B) Şehzadelerin taşra eğitimini üstlenerek sadakat zincirini pekiştirdi.",
            "C) Şehzadelerin taşradan çekilmesiyle fiilen tek icra mercii konumuna geldi.",
            "D) Divan-ı Hümayun'u lağvederek yürütme kararlarını kendi ofisine taşıdı.",
            "E) Taşra yöneticilerine doğrudan bağlı bağımsız bir bürokrasi kurdu."
        ],
        cevap: "C) Şehzadelerin taşradan çekilmesiyle fiilen tek icra mercii konumuna geldi.",
        aciklama: "Finkel, şehzadelerin taşraya gönderilmemesiyle veziriazamın tek icra makamı haline geldiğini vurgulamaktadır. Doğru yanıt C'dir."
    },
    {
        soru: "<i>\"Osmanlı devletinin ateşli silah teknolojisine geçişi, 15. yüzyılın sonlarından itibaren hem endüstriyel hem de kurumsal düzeyde gerçekleşti. Baruthane ve tophane sistemleri devlet kontrolünde tutularak teknoloji transferine olanak tanındı; bu durum Osmanlı'nın ateşli silah konusunda Avrupa devletlerini uzun süre geride bırakmasını sağladı. Ancak yeniçerilerin piyade-ateşli silah kombinasyonuna geçişi, süvari ağırlıklı tımar yapısıyla ciddi bir gerilim yarattı.\"</i><br><br><b>Agoston'un analizine göre Osmanlı'da ateşli silah teknolojisinin kurumsal yansıması nasıl bir iç gerilim doğurdu?</b>",
        secenekler: [
            "A) Baruthane ve tophane sistemleri, kapıkulu birlikleriyle rekabete girişen bağımsız askeri güçlere dönüştü.",
            "B) Ateşli silahların devlet tekelinde üretimi, taşra tüccarlarıyla büyük çaplı çatışmalara zemin hazırladı.",
            "C) Piyade-ateşli silah ağırlıklı Yeniçeri anlayışı, süvari ağırlıklı tımar yapısıyla gerilime yol açtı.",
            "D) Teknoloji transferi, rakip devletlerin üstünlük kazanmasına neden olarak Osmanlı'yı geride bıraktı.",
            "E) Ateşli silah uzmanları devşirme sisteminden değil Avrupa'dan getirildi; bu durum kapıkulunu zayıflattı."
        ],
        cevap: "C) Piyade-ateşli silah ağırlıklı Yeniçeri anlayışı, süvari ağırlıklı tımar yapısıyla gerilime yol açtı.",
        aciklama: "Metin, yeniçerilerin piyade-ateşli silah kombinasyonuna geçişinin süvari ağırlıklı tımar yapısıyla ciddi bir gerilim yarattığını açıkça belirtmektedir. Doğru yanıt C'dir."
    },
    {
        soru: "<i>\"Osmanlı kadıları, yalnızca yargı işlevleriyle sınırlı kalmayıp esnaf denetimi, fiyat belirleme ve şehir altyapısının denetiminden de sorumluydu. Merkezden atanan bu yetkililer, yerel toplulukların şikâyetlerini divana taşıyan bir köprü görevi görüyordu. Ne var ki kadılık kurumu, 17. yüzyılda hızlanan rüşvet ve makam alım satımıyla birlikte güvenilirliğini yitirmeye başladı.\"</i><br><br><b>Faroqhi'nin tanımladığı kadılık kurumunun güvenilirliğini yitirme sürecinin en doğrudan kurumsal sonucu nedir?</b>",
        secenekler: [
            "A) Devletin tüm yargı yetkisini veziriazama devretmek zorunda kalması",
            "B) Merkez ile taşra arasındaki bilgi akışının ve adalet talebinin köprüsünün çökmesi",
            "C) Esnaf loncalarının yargı ve denetim işlevlerini ele geçirmesi",
            "D) Merkezden atanan kadıların yerini seçimle gelen yerel hâkimlerin alması",
            "E) Osmanlı hukuk sisteminin İslam hukukundan örfî hukuka dönüşmesi"
        ],
        cevap: "B) Merkez ile taşra arasındaki bilgi akışının ve adalet talebinin köprüsünün çökmesi",
        aciklama: "Faroqhi, kadıların merkez ile taşra arasında köprü işlevi gördüğünü ve kurumun 17. yüzyılda güvenilirliğini yitirdiğini belirtmektedir. Bu nedenle en doğrudan sonuç, taşradan merkeze ulaşan adalet taleplerinin ve bilgi akışının işlevsizleşmesidir. Doğru yanıt B'dir."
    },
    {
        soru: "<i>\"Osmanlı sancak sistemi, fethedilen toprakların merkeze bağlanmasının idari çerçevesiydi. Sancak, hem mali hem de askeri birlik olarak işlev gördü; sancakbeyi ise dirlik gelirleri üzerinden kapıkulu yerine yerel savaşçıları sefere çıkardı. Bu yapı, 15. ve 16. yüzyıllarda devletin taşra kontrolünü görece düşük bir merkezi maliyet ile sürdürmesine olanak tanıdı.\"</i><br><br><b>Ortaylı'ya göre sancak sisteminin taşra yönetimindeki temel işlevi nedir?</b>",
        secenekler: [
            "A) Taşra halkından doğrudan vergi toplayarak hazineye aktarmak",
            "B) Merkezi orduyu desteklemek için yeniçeri birliklerini barındırmak",
            "C) Hem mali hem askeri birim olarak düşük merkezi maliyetle taşra kontrolünü sağlamak",
            "D) Ulemanın taşra eğitimini düzenlemek ve medrese ağını yönetmek",
            "E) Ticaret yollarını koruma altına alarak gümrük gelirlerini artırmak"
        ],
        cevap: "C) Hem mali hem askeri birim olarak düşük merkezi maliyetle taşra kontrolünü sağlamak",
        aciklama: "Metin, sancak sisteminin hem mali hem askeri işlev gördüğünü ve bunu görece düşük merkezi maliyet ile başardığını açıkça ifade etmektedir. Doğru yanıt C'dir."
    },
    {
        soru: "<i>\"Celali isyanları, yalnızca köylülerin vergi baskısına karşı ayaklanması değil; dağılan tımar sistemi nedeniyle işsiz kalan savaşçıların, kapıkulu emeklilerinin ve serbest dolaşan silahlı grupların bir araya gelmesiyle biçimlenen çok bileşenli bir toplumsal kargaşaydı. Bu kargaşa, Osmanlı idari yapısının taşra üzerindeki kontrolünü köklü biçimde sarstı.\"</i><br><br><b>Griswold'un tanımladığı Celali isyanlarının toplumsal bileşimi, Osmanlı yönetim yapısı hakkında nasıl bir analitik sonuç doğurur?</b>",
        secenekler: [
            "A) İsyanların dini motivasyonunun merkezi otoritenin meşruiyet krizini ortaya koyması",
            "B) Tımar sisteminin çöküşünün silahsız kitleleri değil silahlı ve dağılan askeri unsurları serbest bıraktığını göstermesi",
            "C) Osmanlı'nın taşra kontrolünü yalnızca zor yoluyla değil ekonomik teşviklerle de sağladığını kanıtlaması",
            "D) İsyanların İstanbul'daki kapıkulu birliklerine yönelik halkın tepkisinin doğrudan dışavurumu olması",
            "E) Merkezi yönetimin Celali liderlerini sisteme dahil ederek kontrolü yeniden kurduğunu göstermesi"
        ],
        cevap: "B) Tımar sisteminin çöküşünün silahsız kitleleri değil silahlı ve dağılan askeri unsurları serbest bıraktığını göstermesi",
        aciklama: "Griswold, isyancıların büyük bölümünün tımar sisteminin dağılmasıyla işsiz kalan askerlerden oluştuğunu belirtmektedir. Bu durum, tımar çöküşünün salt ekonomik bir buhrana değil, silahlı güç olan taşra askerlerini merkeze bağlayan bağın kopmasına yol açtığını göstermektedir. Doğru yanıt B'dir."
    },
    {
        soru: "<i>\"16. yüzyılın sonlarında Osmanlı ordu bileşimi köklü bir dönüşüm geçirdi: Atlı dirlik sahipleri yerini yüksek disiplinli ancak maliyetli kapıkulu birlikleri ve yarı düzenli sekban-sarıca gruplarına bıraktı. Bu geçiş, devletin sürekli ve profesyonel kuvvetlere sahip olmasını sağlarken taşra mali dengelerini ağır biçimde bozdu.\"</i><br><br><b>Howard'ın betimlediği ordu bileşimi dönüşümünün taşra mali dengelerine etkisi nasıl analiz edilmelidir?</b>",
        secenekler: [
            "A) Dirlik gelirlerinin kapıkulu maaşlarına aktarılmasıyla tımar sahiplerinin ekonomik gücünün artması",
            "B) Atlı kuvvetlerin yerine geçen profesyonel piyade birliklerinin merkezi hazineden ödenmesi gereğiyle mali baskının yoğunlaşması",
            "C) Sekban-sarıca gruplarının taşra vergilerini doğrudan toplamasıyla köylünün ekonomik yükünün hafiflemiş olması",
            "D) Kapıkulu genişlemesinin tımar ağını güçlendirerek taşra gelirlerini istikrara kavuşturması",
            "E) Profesyonelleşen ordunun ticaret güzergâhlarını korumasıyla gümrük gelirlerinin artış göstermesi"
        ],
        cevap: "B) Atlı kuvvetlerin yerine geçen profesyonel piyade birliklerinin merkezi hazineden ödenmesi gereğiyle mali baskının yoğunlaşması",
        aciklama: "Howard, atlı dirlik sahiplerinin yerini alan kapıkulu ve yarı düzenli birliklerin maliyetli olduğunu ve taşra mali dengelerini bozduğunu belirtmektedir. Bu birliklerin merkezi hazineden ödenmesi gerektiğinden mali baskı yoğunlaşmıştır. Doğru yanıt B'dir."
    },
    {
        soru: "<i>İnalcık: \"Osmanlı siyasi yapısının özü, merkezin taşra üzerindeki katı hiyerarşik kontrolüdür; dirlik sistemi bu kontrolün mali ve askeri aracıydı.\"<br>Barkey: \"Osmanlı imparatorluğunu Avrupa monarşilerinden ayıran, şiddet tekeli değil müzakere ve fark gözetme kapasitesidir; devlet, farklı toplulukları bütünleştiren esnek bir ağ kurdu.\"</i><br><br><b>İnalcık ile Barkey'nin Osmanlı siyasi yapısını açıklayan kavramsal çerçeveleri arasındaki en temel tarih yazımsal gerilim nedir?</b>",
        secenekler: [
            "A) İnalcık Osmanlı'yı durağan bir despotizm olarak tanımlarken Barkey onu kültürel çoğulcu bir demokrasi olarak çerçeveler.",
            "B) İnalcık hiyerarşik-dikey bir kontrol modeli önerirken Barkey müzakere ve çeşitlilik yönetimine dayalı ağsal bir model öne sürmektedir.",
            "C) İnalcık ekonomik faktörleri öncelikli bulurken Barkey askeri gücü merkeze alarak iki tarihçi farklı nedensellik düzeyleri kurmaktadır.",
            "D) Her iki tarihçi de merkezi kontrol anlayışında uzlaşmakta; yalnızca kullandıkları birincil kaynak türleri bakımından ayrışmaktadır.",
            "E) İnalcık devşirme sistemini analizinin odağına alırken Barkey Osmanlı'nın demografik yapısını esas almaktadır."
        ],
        cevap: "B) İnalcık hiyerarşik-dikey bir kontrol modeli önerirken Barkey müzakere ve çeşitlilik yönetimine dayalı ağsal bir model öne sürmektedir.",
        aciklama: "İnalcık, Osmanlı siyasi yapısının özünü hiyerarşik ve dikey bir kontrol mekanizması olarak tanımlarken Barkey müzakere ve fark gözetme kapasitesini ön plana çıkararak yatay bir ağsal model önermektedir. Bu iki çerçeve birbiriyle doğrudan gerilim içindedir. Doğru yanıt B'dir."
    },
    {
        soru: "<i>\"Kanuni Sultan Süleyman döneminde Osmanlı kanunnameleri doruk noktasına ulaştı. Ebu's-suud Efendi'nin şeyhülislamlığı, şeriat ile örfi hukuku uyumlu kılma çabasının simgesidir. Ebu's-suud, padişahın örfi kanunlarını İslam hukuku çerçevesinde yeniden yorumlayarak kurumsallaştırmayı başardı; böylece devlet otoritesiyle dini meşruiyet arasındaki gerilim önemli ölçüde giderildi.\"</i><br><br><b>Imber'ın analizine göre Ebu's-suud Efendi'nin hukuki katkısının siyasi sonucu nedir?</b>",
        secenekler: [
            "A) Şeriatın örfi kanun karsısında üstünlüğünü tesis ederek padişahın kanun koyma yetkisini ortadan kaldırması",
            "B) Örfi kanunların şeriatle bütünleştirilmesiyle devlet otoritesi ile dini meşruiyet arasındaki gerilimin azaltılması",
            "C) Yeni bir Osmanlı hukuk okulu kurarak kadı eğitimini medreselerden bağımsızlaştırması",
            "D) Kanunnameleri lağvederek yalnızca fıkhi hükümlere dayalı bir adalet sistemi oluşturması",
            "E) Eyalet kanunnamelerini İstanbul merkezli tek tip bir hukuk anlayışına dönüştürmesi"
        ],
        cevap: "B) Örfi kanunların şeriatle bütünleştirilmesiyle devlet otoritesi ile dini meşruiyet arasındaki gerilimin azaltılması",
        aciklama: "Metin, Ebu's-suud'un örfi kanunları İslam hukuku çerçevesinde yeniden yorumlayarak şeriatle uyumlu hâle getirdiğini ve bu sayede devlet otoritesiyle dini meşruiyet arasındaki gerilimin azaldığını belirtmektedir. Doğru yanıt B'dir."
    },
    {
        soru: "<i>\"Enderun, devşirme kökenli yetenekli gençlerin seçildiği ve padişahın yakın çevresinde görev alacak biçimde yetiştirilen saray okuludur. Burada verilen eğitim yalnızca askerlik ya da yönetim becerileriyle sınırlı kalmayıp ahlaki, edebi ve felsefi bir terbiyeyi de kapsıyordu. Sistem, devlete sadık ve yetkin bir yönetici kadrosunun yeniden üretilmesini güvence altına alıyordu.\"</i><br><br><b>İtzkowitz'in tanımına göre Enderun sisteminin Osmanlı devlet yapısına sağladığı en temel işlevsel katkı nedir?</b>",
        secenekler: [
            "A) Yeniçerilere liderlik edecek savaş komutanlarını hızla yetiştirmek",
            "B) İslam dünyasından gelen alimler için sarayda bir akademik merkez oluşturmak",
            "C) Devlete bağlı, çok yönlü yetiştirilmiş bir yönetici kadrosunun sürekliliğini sağlamak",
            "D) Osmanlı şehzadelerini yönetim için hazırlayarak veraset krizini önlemek",
            "E) Taşra beylerinin çocuklarını merkeze çekerek yerel güçleri nötralize etmek"
        ],
        cevap: "C) Devlete bağlı, çok yönlü yetiştirilmiş bir yönetici kadrosunun sürekliliğini sağlamak",
        aciklama: "Metin, Enderun'un devlete sadık ve yetkin bir yönetici kadrosunun yeniden üretilmesini güvence altına aldığını açıkça belirtmektedir. Çok yönlü eğitim, sistemin temel işlevini tanımlamaktadır. Doğru yanıt C'dir."
    },
    {
        soru: "<i>\"Osmanlı dirlik sisteminde has, zeamet ve tımar, gelir büyüklüğüne göre ayrışan üç kademe oluşturuyordu. Has, vezir ve sancakbeyi gibi üst yöneticilere; zeamet, orta düzey komutanlara; tımar ise sıradan sipahilere tahsis edildi. Bu hiyerarşi, mali ödüllendirme ile idari-askeri yükümlülükleri doğrusal biçimde ilişkilendiren sistematik bir yapıydı.\"</i><br><br><b>İnalcık'ın aktarımına göre has-zeamet-tımar hiyerarşisinin devlet yönetimi açısından işlevsel önemi nedir?</b>",
        secenekler: [
            "A) Toprak dağılımını eşit biçimde düzenleyerek taşra ile merkez arasındaki gelir farkını ortadan kaldırması",
            "B) Mali ödüllendirmeyi idari ve askeri yükümlülüklerle sistematik olarak ilişkilendirmesi",
            "C) Toprak mülkiyetini kalıtsal biçimde belirleyerek yerel sülaleler oluşturması",
            "D) Vergi toplama yetkisini doğrudan merkezi hazineye devretmesi",
            "E) Yeniçerilerin taşra yönetimine katılımını teşvik etmesi"
        ],
        cevap: "B) Mali ödüllendirmeyi idari ve askeri yükümlülüklerle sistematik olarak ilişkilendirmesi",
        aciklama: "İnalcık, has-zeamet-tımar hiyerarşisinin mali ödüllendirmeyi idari ve askeri yükümlülüklerle doğrusal biçimde ilişkilendiren sistematik bir yapı kurduğunu vurgulamaktadır. Doğru yanıt B'dir."
    },
    {
        soru: "<i>\"17. yüzyılın başlarında Osmanlı mali yönetimi iltizam sistemine giderek daha fazla başvurdu. Vergi toplama hakkının açık artırmayla satılması, kısa vadeli gelir artışı sağlarken uzun vadede taşra halkını ağır biçimde etkileyen vergi sıkıştırmasına zemin hazırladı. Bu dönüşüm, tımar sistemiyle kurulan organik mali-askeri ilişkiyi kopararak devlet-taşra bağını ticarileştirdi.\"</i><br><br><b>Darling'in çerçevelediği iltizam sistemine geçişin devlet yapısı üzerindeki dönüşümsel etkisi nasıl tanımlanabilir?</b>",
        secenekler: [
            "A) Merkezi hazinenin gelirlerini azaltarak devlet iflasına doğrudan zemin hazırlaması",
            "B) Organik mali-askeri tımar ilişkisinin yerini taşra ile ticari bir vergi ilişkisine bırakması",
            "C) Yerel elitin iltizam yoluyla büyük toprak mülkiyeti edinerek Osmanlı soyluluğu oluşturması",
            "D) Kapıkulu birliklerinin iltizam gelirlerini doğrudan ele geçirerek askeri özerklik kazanması",
            "E) Ulema sınıfının vergi yönetimine dahil olmasıyla devletin dini meşruiyetinin güçlenmesi"
        ],
        cevap: "B) Organik mali-askeri tımar ilişkisinin yerini taşra ile ticari bir vergi ilişkisine bırakması",
        aciklama: "Darling, iltizam sisteminin tımar sistemiyle kurulan organik mali-askeri ilişkiyi kopararak devlet-taşra bağını ticarileştirdiğini belirtmektedir. Doğru yanıt B'dir."
    },
    {
        soru: "<i>Kafadar: \"Osmanlı'nın 17. yüzyıl krizi, bir çöküş anlatısından çok değişen uluslararası koşullara ve iç dinamiklere karşı verilen değişken tepkilerin yarattığı bir dönüşüm sürecidir.\"<br>Fleischer: \"17. yüzyıl Osmanlı bürokratları ve entelektüelleri, yaşanan krizi çöküş olarak değil, erdem ve yeterliliğe dayalı eski düzenin tahrip edilmesi olarak yorumladı; bu nedenle önerilen reçeteler modernleşme değil, ahlaki yeniden tesis çağrısını içeriyordu.\"</i><br><br><b>Kafadar ile Fleischer'ın 17. yüzyıl Osmanlı krizine yaklaşımlarını karşılaştırdığınızda, nasıl bir tarihsel analiz ortaya çıkmaktadır?</b>",
        secenekler: [
            "A) Kafadar dönüşümü dışsal dinamiklerle açıklarken Fleischer Osmanlı bürokratlarının içsel ahlaki çerçevesine odaklanır; iki yaklaşım birbirini tamamlar.",
            "B) Her iki tarihçi de krizi 'çöküş' teriminin en dar anlamıyla kavrayarak yapısal çözülmeyi ön plana çıkarmaktadır.",
            "C) Kafadar dönemin bürokratlarının ahlaki tutumunu çözümleme aracı olarak kullanırken Fleischer yapısal dönüşüm hipotezini savunmaktadır.",
            "D) İki tarihçi de krizin başlıca nedenini Celali isyanlarında aramakta; yalnızca sonuçları bakımından ayrışmaktadır.",
            "E) Fleischer Osmanlı'nın uluslararası arenadaki gücünü ölçütleme yolunu seçerken Kafadar kurumların verimliliğini merkeze almaktadır."
        ],
        cevap: "A) Kafadar dönüşümü dışsal dinamiklerle açıklarken Fleischer Osmanlı bürokratlarının içsel ahlaki çerçevesine odaklanır; iki yaklaşım birbirini tamamlar.",
        aciklama: "Kafadar, krizi dışsal ve iç dinamiklere verilen değişken tepkilerle açıklayan bir dönüşüm çerçevesi sunarken Fleischer dönemin bürokratlarının ve entelektüellerinin krizi 'ahlaki tahribat' olarak algıladığını ve ahlaki yeniden tesis çağrısında bulunduğunu ortaya koymaktadır. Doğru yanıt A'dır."
    },
    {
        soru: "<i>\"Osmanlı yönetim anlayışı, hükümdarın hem İslam halifesi hem de dünyanın efendisi olduğu evrensel bir egemenlik iddiasına dayanıyordu. Bu ikili meşruiyet zemini, Osmanlı'nın fetih politikasını salt toprak kazanımı değil, evrensel adaletin tesisi olarak sunmasına olanak tanıdı.\"</i><br><br><b>Goffman'ın aktardığı ikili meşruiyet anlayışının Osmanlı yönetim ideolojisi açısından ne gibi pratik bir işlevi vardı?</b>",
        secenekler: [
            "A) Osmanlı padişahlarının Avrupa'daki siyasi meşruiyetini pekiştirerek uluslararası ittifakları kolaylaştırması",
            "B) Fethi salt askeri bir kazanım değil, evrensel adalet ve egemenlik iddiası biçiminde sunmayı sağlaması",
            "C) Şeyhülislamın dinî bir denetçi olarak padişahın yetkisini sınırlandırmasına zemin hazırlaması",
            "D) Osmanlı'nın Abbasiler sonrası İslam dünyasında hilafeti üstlenerek dini önderin salt Osmanlı sülalesiyle özdeşleşmesi",
            "E) Devşirme sisteminin İslam hukukuna uygunluğunu meşrulaştırarak Hiristiyan nüfustan çocuk alınmasına gerekçe sunması"
        ],
        cevap: "B) Fethi salt askeri bir kazanım değil, evrensel adalet ve egemenlik iddiası biçiminde sunmayı sağlaması",
        aciklama: "Goffman, Osmanlı'nın ikili meşruiyet zemini sayesinde fetih politikasını evrensel adaletin tesisi olarak çerçevelediğini belirtmektedir. Doğru yanıt B'dir."
    }
];
window.allTests = window.allTests || {};

window.allTests["klasik_u3_degisim_1"] = [
    {
        soru: "<i>\"Osmanlı kanunnamelerinin özgün yanı, İslam hukukunun yanı sıra sultani örfü de yazılı hale getirmesiydi. Fatih Sultan Mehmed döneminde derlenen kanunnameler, saray protokolünden vergi oranlarına, ceza hukukundan arazi yönetimine kadar devletin her alanını düzenliyordu. Bu kanunlar şeriata aykırı olmamak kaydıyla geçerliydi; ancak örfü yasalaştıran sultanın kendisiydi.\"</i><br><br><b>Bu metinden hareketle Osmanlı kanunname geleneğinin hukuki temellerini açıklayınız. Şeriat ile örfi hukuk arasındaki ilişkiyi ve bu ikili yapının devlet yönetimine katkısını analiz ediniz.</b>",
        cevap: "Osmanlı kanunname geleneği, şeriatın (İslam fıkhı) sabit normları ile sultanın iradesiyle oluşan esnek örfi düzenlemelerin bütünleşmesine dayanır[cite: 256]. Fatih kanunnamesi toprak hukuku, miras, ceza ve saray protokolü gibi geniş bir alanı düzenleyerek hukuki boşlukları doldurmuştur[cite: 256]. Bu ikili yapıda teoride şeriat öncelikli olsa da, pratikte örfün fiili geçerliliği yönetimde büyük bir esneklik sağlamış ve devletin farklı bölgelerdeki ihtiyaçlarına hızlı yanıt vermesine katkıda bulunmuştur[cite: 256, 338, 339]."
    },
    {
        soru: "<i>\"16. yüzyılın sonlarından itibaren Osmanlı'da yeni bir siyasi aktör grubu ortaya çıktı: kapıkulu süvari ve piyadeleri gibi maaşlı asker kitleleri, artık yalnızca savaş meydanında değil saray ve başkent siyasetinde de belirleyici bir güç hâline geldi. Bu gelişme, iktidarın saltanat tekeline karşı çoğullaştığı 'ikinci Osmanlı İmparatorluğu'nun başlangıcını işaretliyordu.\"</i><br><br><b>Tezcan'ın 'ikinci Osmanlı İmparatorluğu' kavramını açıklayınız. Kapıkulu askerlerinin siyasi aktöre dönüşmesinin nedenlerini ve bu dönüşümün saray iktidarıyla ilişkisini değerlendiriniz.</b>",
        cevap: "Tezcan'ın 'ikinci imparatorluk' kavramı, iktidarın tek bir sultanın tekelinden çıkarak farklı odakların (ordu, bürokrasi, ulema) rekabet ettiği daha çoğulcu bir yapıya geçişini tanımlar[cite: 259, 341]. Kapıkulu askerleri; artan nüfus, uzun süren savaşlar, düzensiz maaş ödemeleri ve ocak kimliğinin güçlenmesi gibi nedenlerle siyasallaşmıştır[cite: 341]. Bu dönüşüm, saray ile asker arasındaki gerilimi artırmış ve klasik devşirme-kul sisteminin sultan üzerindeki mutlak sadakat bağını zayıflatarak saray iktidarını askeri müdahalelere açık hale getirmiştir[cite: 341]."
    },
    {
        soru: "<i>\"Vezir-i azam Koca Sinan Paşa, bir Divan toplantısında diğer vezirlerin görüşlerini almaksızın sefere karar verdi. Hazine bu seferi karşılayacak güçte değildi; yeniçeriler ise uzun süredir sefer ikramiyesi beklemekteydi. Selaniki bu durumu şöyle özetler: 'Devlet işleri artık şura ile değil bir kişinin deli cesareti ile yürür olmuştu.'\"</i><br><br><b>Bu birincil kaynaktan hareketle 16. yüzyılın sonlarında Osmanlı Divan-ı Hümayun'unda karar alma sürecinin nasıl dönüştüğünü analiz ediniz. 'Şura' geleneğinin çözülmesini ve bunun devlet yönetimine etkisini tartışınız.</b>",
        cevap: "Divan-ı Hümayun'un temel ilkesi olan kolektif danışma (şura), yerini zamanla bireysel kararlara ve sadrazamın mutlak nüfuzuna bırakmıştır[cite: 262, 343]. Sultanın Divan başkanlığından çekilmesi ve sadrazamın tam yetkiyle donanması, diğer vezirlerin görüşlerinin ihmal edilmesine yol açmıştır[cite: 343]. Bu dönüşüm, Koca Sinan Paşa örneğinde görüldüğü gibi, mali sürdürülebilirlik gözetilmeden alınan kararlara ve dolayısıyla devlet yönetiminde stratejik ve ekonomik krizlere neden olmuştur[cite: 262, 343]."
    },
    {
        soru: "<i>\"Osmanlı ordusunun 17. yüzyıl boyunca yaşadığı kurumsal bozulma, yalnızca yeniçerilerin disiplinsizleşmesiyle açıklanamaz. Cavalieri denen hafif süvari birlikleri de aynı dönemde savaş verimliliğini yitirdi; daha da önemlisi, ordunun piyade-topçu-süvari koordinasyonu giderek zayıfladı. Osmanlı ordusu artık farklı parçalarının toplamından ibaret kalmaya başladı.\"</i><br><br><b>Bu metinden hareketle Osmanlı ordusunun 17. yüzyıldaki bozulmasını tek bir kurumun (yeniçeri) çöküşüyle açıklamanın neden yetersiz kaldığını tartışınız. Farklı ordu birimlerinin koordinasyonunun neden stratejik öneme sahip olduğunu analiz ediniz.</b>",
        cevap: "Aksan'a göre ordu bozulması sadece yeniçeriyle sınırlı değildir; hafif süvari birlikleri (cavalieri) ve akıncılar gibi tüm unsurlar eş zamanlı olarak verimliliğini yitirmiştir[cite: 266, 345]. Ordunun gücü parçaların toplamından değil, piyade, topçu ve süvari birimlerinin koordinasyonundan doğmaktaydı[cite: 266]. Bu koordinasyonun zayıflaması, ordunun savaş alanındaki taktik bütünlüğünü ve stratejik manevra kabiliyetini yok ederek askeri başarısızlıkların temel nedeni haline gelmiştir[cite: 266, 345]."
    },
    {
        soru: "<i>\"Devletin hastalığı dörttür: Birincisi hazinede altın kalmamıştır. İkincisi asker çoğalmış, liyakatsiz olanlar da arasına karışmıştır. Üçüncüsü eyalet valileri halkı soyup soğana çevirmiştir. Dördüncüsü ise ilim ehlinin devlet işlerinden uzaklaştırılmış olmasıdır. Bu dört derde çare bulunmadıkça devletin ıslahı mümkün değildir.\"</i><br><br><b>Katip Çelebi'nin bu teşhisini çerçeve olarak kullanarak 17. yüzyıl Osmanlı devletinin yönetim krizini analiz ediniz. Öne sürdüğü dört sorunu birbirleriyle ilişkilendirerek sistematik bir değerlendirme yapınız.</b>",
        cevap: "Katip Çelebi, krizi mali (altın eksikliği), askeri (niteliksiz asker artışı), idari (taşra valilerinin zulmü) ve entelektüel (alimlerin dışlanması) olmak üzere dört temel nedene bağlar[cite: 270, 347]. Bu sorunlar birbirini besleyen bir nedensellik zinciri oluşturur: Mali açıklar maaşların gecikmesine ve disiplinsiz askeri sınıfların doğmasına; liyakatsiz atamalar taşra yönetiminin bozulmasına; taşradaki yolsuzluklar ise vergi tabanının çökerek mali krizin derinleşmesine yol açmaktadır[cite: 347, 348]."
    },
    {
        soru: "<i>\"Osmanlı sınır politikası yalnızca fetih hedefli değildi; sınır ötesi tampon bölgeler ve vassal devletler, imparatorluğun doğrudan yönetmekte güçlük çektiği toprakları yönetmenin maliyetini düşürüyordu. Macaristan'ın 1541'de eyalete dönüştürülmesi, Transilvanya'nın ise vassal olarak bırakılması bu pragmatik stratejinin somut yansımasıydı.\"</i><br><br><b>Bu metinden hareketle Osmanlı'nın sınır yönetimi ve vassal devlet politikasını analiz ediniz. Doğrudan yönetim ile vassal yönetim arasındaki tercihin hangi kriterlere bağlı olduğunu ve bu stratejinin Osmanlı'ya sağladığı avantajları tartışınız.</b>",
        cevap: "Osmanlı, sınır yönetiminde stratejik önem, yerel direnç ve idari maliyeti gözeterek pragmatik bir model izlemiştir[cite: 274, 350]. Transilvanya, Eflak ve Boğdan gibi bölgeler vassal olarak bırakılarak tampon bölge işlevi görmüş ve düşük idari maliyetle vergi ve asker kaynağı olarak kullanılmıştır[cite: 274, 350]. Doğrudan yönetime (eyalet) ancak stratejik risklerin arttığı ve idari kapasitenin yettiği durumlarda geçilmiştir; bu esneklik imparatorluk genişlemesini sürdürülebilir kılmıştır[cite: 350]."
    },
    {
        soru: "<i>\"Eski zamanda her eyaletin valisi hem sancaklarının askerini toplayıp sefere getirmek hem de memleketin güvenliğini sağlamak ile mükellef idi. Şimdiki hâlde ise valiler sancakları elinden çıkmış, hazine geliri azalmış, asker sayısı belirli bir çerçeveye girmiş; vali adı kalmış ama gücü kalmamıştır.\"</i><br><br><b>Hezarfen'in bu gözleminden hareketle Osmanlı eyalet valiliğinin yüzyıllar içinde geçirdiği dönüşümü analiz ediniz. 'Ad kalıp güç kalmama' olgusunun merkezileşme politikasıyla çelişkisini açıklayınız.</b>",
        cevap: "Kuruluş döneminde eyalet valileri askeri, mali ve idari yetkileri şahıslarında birleştiren güçlü figürlerken, 17. yüzyılda bu yetkiler parçalanmıştır[cite: 278, 352]. Merkezileşme politikası kağıt üzerinde valileri daha sıkı denetlemek istese de, valilerin kaynaklarının (sancak ve gelir) ellerinden alınması taşrada büyük bir otorite boşluğu yaratmıştır[cite: 353]. Bu durum, valilerin yerel güvenliği sağlayamamasına ve zamanla yerel âyanların bu boşluğu doldurarak merkeze rakip olmasına zemin hazırlamıştır[cite: 353]."
    },
    {
        soru: "<i>\"Sultan İbrahim Han zamanında yeniçeri ocağından iki üç yüz kişi Topkapı Sarayı'na yürüyüş yaptı. Sadrazam ve vezirlerin kapılarını döverek içeri girdiler; hazineden maaş istediler. Padişah bu hadiseyi duyunca hayrete düştü; lakin sarayın kapılarını açtırmak zorunda kaldı. Ocak artık sarayın içine giriyordu.\"</i><br><br><b>Bu birincil kaynak pasajından hareketle 17. yüzyılda yeniçerilerin saray siyasetine doğrudan müdahalesini Osmanlı iktidar dengeleri açısından değerlendiriniz. Bu gelişmenin kul-efendi ilişkisini nasıl tersine çevirdiğini analiz ediniz.</b>",
        cevap: "Naima'nın aktardığı olay, sultanın ordusu üzerindeki mutlak otoritesinin sarsıldığını ve sarayın fiziki-siyasi dokunulmazlığının ihlal edildiğini gösterir[cite: 282, 355]. Klasik dönemde sultanın 'kulu' olan ve mutlak itaat beklenen yeniçeri, artık taleplerini saray kapısına dayanarak dayatan bağımsız bir siyasi aktöre dönüşmüştür[cite: 355]. Bu müdahale, kul-efendi ilişkisini tersine çevirerek yeniçeri ocağını sultanları tahttan indiren ve yönetimi belirleyen bir vesayet odağı haline getirmiştir[cite: 355]."
    },
    {
        soru: "<i>\"Osmanlı'da şehzadelerin taşraya gönderilmesi ve orada idari deneyim kazanması, hem devlet adamı yetiştiren hem de şehzadeyi tehlikeli başkent siyasetinden uzak tutan bir mekanizmaydı. 16. yüzyılın ortasından itibaren bu uygulamanın zayıflamasıyla birlikte hanedan mensupları sarayda tutulmaya başlandı; bu değişim şehzade yetiştirme ve halef belirsizliği açısından derin sonuçlar doğurdu.\"</i><br><br><b>Bu metinden hareketle Osmanlı şehzade eğitimi ve sancağa çıkma geleneğinin işlevlerini analiz ediniz. Bu uygulamanın terkedilmesinin hanedan ve devlet açısından yarattığı sonuçları tartışınız.</b>",
        cevap: "Sancağa çıkma geleneği; şehzadeye taşra deneyimi kazandırmak, yönetim becerilerini geliştirmek ve başkentteki fitnelerden uzak tutmak gibi hayati işlevlere sahipti[cite: 286, 357]. Bu geleneğin yerini alan sarayda tutulma (kafes) sistemi, devlet idaresinden bihaber ve psikolojik olarak yetersiz haleflerin yetişmesine yol açmıştır[cite: 357]. Tecrübesiz hükümdarların tahta geçmesi, saray bürokrasisi ve valide sultanların yönetimdeki etkisini artırarak devleti isyan ve darbelere karşı daha kırılgan hale getirmiştir[cite: 357]."
    },
    {
        soru: "<i>\"Osmanlı'da devşirme kurumu 17. yüzyılda çökmeden önce en az iki nesil boyunca aşınma yaşamıştı. Müslüman çocukların da devşirme listelerine dahil edilmesi, öte yandan kapıkulu ocaklarındaki listelerin babadan oğula geçmesi, sistemin özgün ilkesiyle doğrudan çelişiyordu. Bu süreçte kapıkulu ordusu hem siyasi bağımsızlık hem de ekonomik güç kazandı.\"</i><br><br><b>Bu metinden hareketle devşirme sisteminin çöküş sürecini aşamalı bir bozulma süreci olarak analiz ediniz. Sistemin özgün ilkeleri ile gerçek uygulama arasındaki uçurumun nasıl derinleştiğini açıklayınız.</b>",
        cevap: "Devşirme sistemi, yerel aile bağları olmayan ve sadece sultana bağlı Hristiyan çocukların yetiştirilmesi ilkesine dayanmaktaydı[cite: 290, 359]. Ancak Müslümanların sisteme dahil edilmesi ve kadroların babadan oğula (kuloğlu sistemi) geçmeye başlaması, bu liyakat ve sadakat temelini bozmuştur[cite: 290, 359]. Kurumsal bozulma ani bir kırılma değil, iki nesle yayılan bir erozyonla gerçekleşmiş; ocak kimliği sultanın otoritesinin önüne geçerek askeri yapının siyasi ve ekonomik bir baskı grubuna dönüşmesine neden olmuştur[cite: 290, 360]."
    }
];
